import heapq

class WeightedGraph:
    def __init__(self):
        self.graph = {}

    def add_node(self, node):
        if node not in self.graph:
            self.graph[node] = {}

    def add_edge(self, node1, node2, weight, directed=False):
        self.add_node(node1)
        self.add_node(node2)

        self.graph[node1][node2] = weight
        if not directed:
            self.graph[node2][node1] = weight

    def dijkstra(self, start_node):
        if start_node not in self.graph:
            raise ValueError(f"Başlangıç düğümü '{start_node}' grafikte bulunmuyor.")

        distances = {node: float('infinity') for node in self.graph}
        distances[start_node] = 0

        previous_nodes = {node: None for node in self.graph}

        priority_queue = [(0, start_node)] # (mesafe, düğüm)

        while priority_queue:
            current_distance, current_node = heapq.heappop(priority_queue)

            if current_distance > distances[current_node]:
                continue

            for neighbor, weight in self.graph[current_node].items():
                distance = current_distance + weight

                if distance < distances[neighbor]:
                    distances[neighbor] = distance
                    previous_nodes[neighbor] = current_node
                    heapq.heappush(priority_queue, (distance, neighbor))

        return distances, previous_nodes

    def reconstruct_path(self, previous_nodes, start_node, target_node):
        path = []
        current = target_node
        while current is not None:
            path.insert(0, current)
            current = previous_nodes[current]

        if path and path[0] == start_node:
            return path
        return []

if __name__ == '__main__':
    # Örnek kullanım
    graph = WeightedGraph()

    # Düğümleri ekle
    graph.add_node('A')
    graph.add_node('B')
    graph.add_node('C')
    graph.add_node('D')
    graph.add_node('E')
    graph.add_node('F')

    # Yönsüz kenarları ekle (varsayılan)
    graph.add_edge('A', 'B', 7)
    graph.add_edge('A', 'C', 9)
    graph.add_edge('A', 'F', 14)
    graph.add_edge('B', 'C', 10)
    graph.add_edge('B', 'D', 15)
    graph.add_edge('C', 'D', 11)
    graph.add_edge('C', 'F', 2)
    graph.add_edge('D', 'E', 6)
    graph.add_edge('E', 'F', 9)

    start_node = 'A'
    distances, previous_nodes = graph.dijkstra(start_node)

    print(f"Başlangıç düğümü '{start_node}' için en kısa mesafeler:")
    for node, dist in distances.items():
        if dist == float('infinity'):
            print(f"  {node}: Erişilemez")
        else:
            print(f"  {node}: {dist}")

    print("\nEn kısa yollar:")
    for target_node in graph.graph:
        if target_node == start_node:
            continue
        path = graph.reconstruct_path(previous_nodes, start_node, target_node)
        if path:
            print(f"  {start_node} -> {target_node}: {' -> '.join(path)} (Mesafe: {distances[target_node]})")
        else:
            print(f"  {start_node} -> {target_node}: Yol bulunamadı.")


